#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int tim,dfn[N],low[N],cnt,vis[N],n,m,chu[N],a[N],vis2[N],vis3[N],ans;
vector<int> G[N];
stack<int> st;
void tarjan(int u)
{
	dfn[u]=low[u]=++tim;
	st.push(u);
	for(int i=0;i<G[u].size();i++)
    {
		int v=G[u][i];
		if(dfn[v]==0)
        {
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v]==0)
        {
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
    {
        int cnt2=0;
		cnt++;
		while(true)
        {
            cnt2++;
			int now=st.top();
			st.pop();
			vis[now]=cnt;
            vis2[cnt]=cnt2;
			if(now==u) break;
		}
	}
}
int main()
{
    cin>>n>>m;
    memset(vis2,0x3f,sizeof(vis2));
    for(int i=1;i<=m;i++)
    {
        int u,v;
        cin>>u>>v;
        G[u].push_back(v);
    }
	for(int i=1;i<=n;i++)
    {
		if(vis[i]==0)
        {
			tarjan(i);
		}
    }
	for(int u=1;u<=n;u++)
    {
		for(int i=0;i<G[u].size();i++)
        {
			int v=G[u][i];
			if(vis[u]!=vis[v])
            {
                chu[vis[u]]++;
			}	
		}	
	}
    int ch=-1;
    for(int i=1;i<=cnt;i++)
    {
        if(chu[i]==0)
        {
            if(ch!=-1)
            {
                cout<<0;
                return 0;
            }
            else ch=i;
        }
    }
    cout<<vis2[ch];
	return 0;
}
